double* allocate_2d_matrix(int rows, int cols) {
    if (rows <= 0 || cols <= 0) {
        return NULL;
    }

    size_t total_elements = (size_t)rows * cols;

    if (total_elements > (SIZE_MAX / sizeof(double))) {
        return NULL;
    }

    size_t total_bytes = total_elements * sizeof(double);

    double* matrix = (double*)malloc(total_bytes);

    return matrix;
}